import React, { useState, useEffect } from "react";
import "./BatchAnalysis.css";

function BatchAnalysis({ onFileChange, onAnalyze, loading, results, selectedFile }) {
  const [filteredData, setFilteredData] = useState(null);
  const [filters, setFilters] = useState({
    riskLevels: [],
    tenureRange: [0, 200],
    ordersRange: [0, 100]
  });
  const [activeTab, setActiveTab] = useState('scorecard');
  const [analyticsData, setAnalyticsData] = useState(null);

  const handleFileSelect = (e) => {
    if (e.target.files.length > 0) {
      onFileChange(e);
      setFilteredData(null);
      setAnalyticsData(null);
      setFilters({
        riskLevels: [],
        tenureRange: [0, 200],
        ordersRange: [0, 100]
      });
    }
  };

  // Apply filters when results change
  useEffect(() => {
    if (results && results.sample_predictions) {
      applyFilters(results.sample_predictions, filters);
      setAnalyticsData(results.analytics_data);
    }
  }, [results, filters]);

  const applyFilters = (data, filterSettings) => {
    let filtered = [...data];
    
    if (filterSettings.riskLevels.length > 0) {
      filtered = filtered.filter(item => 
        filterSettings.riskLevels.includes(item.Risk_Level)
      );
    }
    
    filtered = filtered.filter(item => 
      item.Tenure >= filterSettings.tenureRange[0] && 
      item.Tenure <= filterSettings.tenureRange[1] &&
      item.OrderCount >= filterSettings.ordersRange[0] && 
      item.OrderCount <= filterSettings.ordersRange[1]
    );
    
    setFilteredData(filtered);
  };

  const handleFilterChange = (filterType, value) => {
    const newFilters = { ...filters, [filterType]: value };
    setFilters(newFilters);
  };

  const renderRiskDistributionChart = () => {
    if (!analyticsData || !analyticsData.risk_distribution) return null;
    
    const { labels, values, colors } = analyticsData.risk_distribution;
    const total = values.reduce((sum, val) => sum + val, 0);

    return (
      <div className="chart-container">
        <h4>📊 Customer Distribution by Risk Level</h4>
        <div className="bar-chart">
          {labels.map((label, index) => {
            const percentage = ((values[index] / total) * 100).toFixed(1);
            return (
              <div key={index} className="bar-item">
                <div className="bar-label">{label}</div>
                <div className="bar-track">
                  <div 
                    className="bar-fill" 
                    style={{ 
                      width: `${percentage}%`,
                      backgroundColor: colors[index]
                    }}
                  >
                    <span className="bar-value">{values[index]} ({percentage}%)</span>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    );
  };

  const renderProbabilityDistribution = () => {
    if (!analyticsData || !analyticsData.probability_distribution) return null;

    const { bins, counts } = analyticsData.probability_distribution;
    const maxCount = Math.max(...counts);

    return (
      <div className="chart-container">
        <h4>📈 Distribution of Churn Probabilities</h4>
        <div className="histogram">
          {bins.map((bin, index) => (
            <div key={index} className="histogram-bar">
              <div 
                className="histogram-fill"
                style={{ 
                  height: `${(counts[index] / maxCount) * 100}%`,
                  backgroundColor: '#06b6d4'
                }}
              >
                <span className="histogram-count">{counts[index]}</span>
              </div>
              <div className="histogram-label">{bin}</div>
            </div>
          ))}
        </div>
      </div>
    );
  };

  const renderFeatureAnalysis = () => {
    if (!analyticsData || !analyticsData.feature_analysis) return null;

    const features = ['Tenure', 'CashbackAmount', 'DaySinceLastOrder', 'SatisfactionScore', 'OrderCount'];
    
    return features.slice(0, 3).map(feature => {
      const featureData = analyticsData.feature_analysis[feature];
      if (!featureData) return null;

      return (
        <div key={feature} className="chart-container">
          <h4>📋 {feature} Analysis by Risk Level</h4>
          <div className="stats-table">
            <table>
              <thead>
                <tr>
                  <th>Risk Level</th>
                  <th>Count</th>
                  <th>Average</th>
                  <th>Median</th>
                  <th>Min</th>
                  <th>Max</th>
                </tr>
              </thead>
              <tbody>
                {featureData.map((stat, index) => (
                  <tr key={index}>
                    <td>{stat.risk_level.split(':')[0]}</td>
                    <td>{filteredData ? filteredData.filter(item => item.Risk_Level === stat.risk_level).length : 'N/A'}</td>
                    <td>{stat.mean?.toFixed(1) || 'N/A'}</td>
                    <td>{stat.median?.toFixed(1) || 'N/A'}</td>
                    <td>{stat.min?.toFixed(1) || 'N/A'}</td>
                    <td>{stat.max?.toFixed(1) || 'N/A'}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      );
    });
  };

  const renderValueRiskAnalysis = () => {
    if (!analyticsData || !analyticsData.value_risk_analysis) return null;

    const scatterData = analyticsData.value_risk_analysis;
    const riskGroups = {
      high: scatterData.filter(item => item.riskLevel.includes('High')),
      medium: scatterData.filter(item => item.riskLevel.includes('Moderate')),
      low: scatterData.filter(item => item.riskLevel.includes('Low'))
    };

    return (
      <div className="chart-container">
        <h4>💰 Customer Value vs Churn Risk Analysis</h4>
        <div className="scatter-summary">
          <div className="risk-group high-risk">
            <h5>🚨 High Risk Customers</h5>
            <p>Count: {riskGroups.high.length}</p>
            <p>Avg Value: ₹{(riskGroups.high.reduce((sum, item) => sum + item.customerValue, 0) / riskGroups.high.length || 0).toLocaleString()}</p>
            <p>Avg Risk: {(riskGroups.high.reduce((sum, item) => sum + item.churnProbability, 0) / riskGroups.high.length || 0).toFixed(1)}%</p>
          </div>
          <div className="risk-group medium-risk">
            <h5>⚠️ Medium Risk Customers</h5>
            <p>Count: {riskGroups.medium.length}</p>
            <p>Avg Value: ₹{(riskGroups.medium.reduce((sum, item) => sum + item.customerValue, 0) / riskGroups.medium.length || 0).toLocaleString()}</p>
            <p>Avg Risk: {(riskGroups.medium.reduce((sum, item) => sum + item.churnProbability, 0) / riskGroups.medium.length || 0).toFixed(1)}%</p>
          </div>
          <div className="risk-group low-risk">
            <h5>✅ Low Risk Customers</h5>
            <p>Count: {riskGroups.low.length}</p>
            <p>Avg Value: ₹{(riskGroups.low.reduce((sum, item) => sum + item.customerValue, 0) / riskGroups.low.length || 0).toLocaleString()}</p>
            <p>Avg Risk: {(riskGroups.low.reduce((sum, item) => sum + item.churnProbability, 0) / riskGroups.low.length || 0).toFixed(1)}%</p>
          </div>
        </div>
      </div>
    );
  };

  const renderSegmentCard = (segmentData, riskLevel, color, icon, label) => {
    if (!segmentData || segmentData.length === 0) return null;

    const count = segmentData.length;
    const avgChurn = (segmentData.reduce((sum, item) => sum + item.Churn_Probability, 0) / count) * 100;
    const avgRecency = segmentData.reduce((sum, item) => sum + (item.DaySinceLastOrder || 0), 0) / count;
    const avgOrders = segmentData.reduce((sum, item) => sum + (item.OrderCount || 0), 0) / count;

    // Get recommendations from backend if available
    let recommendations = [];
    if (results && results.segment_insights && results.segment_insights[label]) {
      recommendations = results.segment_insights[label].recommendations || [];
    } else {
      // Fallback recommendations
      if (riskLevel === 'High') {
        recommendations = [
          "Immediate executive-level 1:1 outreach within 24 hours",
          "Offer premium, non-monetary incentives",
          "Conduct root cause analysis of last 3 interactions",
          "Assign dedicated customer success manager"
        ];
      } else if (riskLevel === 'Medium') {
        recommendations = [
          "Deploy high-value personalized offers within 7 days",
          "Send satisfaction survey to identify pain points",
          "Provide personalized product recommendations",
          "Offer loyalty program tier upgrade"
        ];
      } else {
        recommendations = [
          "Enroll in advocacy/referral program",
          "Send educational content and usage tips",
          "Offer cross-sell opportunities",
          "Maintain regular value communication"
        ];
      }
    }

    // Prepare CSV download
    const csvData = segmentData.map(item => ({
      CustomerID: item.CustomerID || 'N/A',
      Tenure: item.Tenure,
      OrderCount: item.OrderCount,
      CashbackAmount: item.CashbackAmount,
      DaySinceLastOrder: item.DaySinceLastOrder,
      SatisfactionScore: item.SatisfactionScore,
      Churn_Probability: (item.Churn_Probability * 100).toFixed(2) + '%',
      Risk_Level: item.Risk_Level,
      Predicted_Churn: item.Predicted_Churn
    }));

    const csvContent = [
      Object.keys(csvData[0]).join(','),
      ...csvData.map(row => Object.values(row).join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv' });
    const url = URL.createObjectURL(blob);

    return (
      <div className="segment-card">
        <div className="segment-header">
          <div className="segment-title" style={{ color }}>
            {icon} {label} ({count} Customers)
          </div>
          <span className="segment-priority">Priority: {riskLevel}</span>
        </div>
        
        <div className="segment-metrics">
          <div className="metric">
            <div className="metric-label">Avg. Churn Prob.</div>
            <div className="metric-value">{avgChurn.toFixed(1)}%</div>
          </div>
          <div className="metric">
            <div className="metric-label">Avg. Days Inactive</div>
            <div className="metric-value">{avgRecency.toFixed(1)} days</div>
          </div>
          <div className="metric">
            <div className="metric-label">Avg. Orders</div>
            <div className="metric-value">{avgOrders.toFixed(1)}</div>
          </div>
        </div>

        <div className="segment-recommendations">
          <div className="recommendation-title" style={{ color }}>
            {riskLevel === 'High' ? '🚨 CRITICAL INTERVENTION' : 
             riskLevel === 'Medium' ? '⚠️ PROACTIVE ENGAGEMENT' : '✅ LOYALTY MAXIMIZATION'}
          </div>
          <ul>
            {recommendations.map((rec, index) => (
              <li key={index}>{rec}</li>
            ))}
          </ul>
        </div>

        <a 
          href={url} 
          download={`${riskLevel.toLowerCase()}_risk_customers.csv`}
          className="download-btn"
        >
          📥 Download {riskLevel} Segment CSV
        </a>
      </div>
    );
  };

  const renderExecutiveScorecard = () => {
    if (!results) return null;

    const { summary, business_impact } = results;
    const displayData = filteredData || results.sample_predictions || [];

    const totalCustomers = summary?.total_customers_processed || displayData.length;
    const highRiskCount = summary?.risk_distribution?.['P1: High Risk (>70%)'] || 
                         displayData.filter(item => item.Risk_Level === 'P1: High Risk (>70%)').length;

    return (
      <div className="executive-scorecard">
        <h3>⭐ Executive Scorecard</h3>
        <div className="scorecard-subtitle">
          {results.data_source === 'simulated' ? 'Demo Data Analysis' : 'Uploaded Data Analysis'} • 
          Processed in {results.processing_time_seconds || 'N/A'}s
        </div>
        
        <div className="kpi-grid">
          <div className="kpi-card">
            <div className="kpi-title">Total Customers Processed</div>
            <div className="kpi-value">{totalCustomers.toLocaleString()}</div>
          </div>
          
          <div className="kpi-card">
            <div className="kpi-title">High-Risk Customers</div>
            <div className="kpi-value">{highRiskCount} ({(highRiskCount/totalCustomers*100).toFixed(1)}%)</div>
          </div>
          
          <div className="kpi-card">
            <div className="kpi-title">Potential Revenue Loss</div>
            <div className="kpi-value">₹{(business_impact?.total_potential_loss / 100000).toFixed(1)}L</div>
          </div>
          
          <div className="kpi-card">
            <div className="kpi-title">ROI on Retention</div>
            <div className="kpi-value">{business_impact?.roi_retention?.toFixed(1) || 'N/A'}x</div>
          </div>
        </div>

        {business_impact?.segment_breakdown && (
          <div className="segment-breakdown">
            <h4>📈 Segment Performance Metrics</h4>
            <div className="segment-metrics-grid">
              <div className="segment-metric high-risk">
                <h5>🚨 High Risk Segment</h5>
                <p>Customers: {business_impact.segment_breakdown.high_risk.count}</p>
                <p>Avg Probability: {(business_impact.segment_breakdown.high_risk.avg_probability * 100).toFixed(1)}%</p>
                <p>Potential Loss: ₹{(business_impact.segment_breakdown.high_risk.potential_loss / 1000).toFixed(0)}K</p>
              </div>
              <div className="segment-metric medium-risk">
                <h5>⚠️ Medium Risk Segment</h5>
                <p>Customers: {business_impact.segment_breakdown.medium_risk.count}</p>
                <p>Avg Probability: {(business_impact.segment_breakdown.medium_risk.avg_probability * 100).toFixed(1)}%</p>
                <p>Potential Loss: ₹{(business_impact.segment_breakdown.medium_risk.potential_loss / 1000).toFixed(0)}K</p>
              </div>
              <div className="segment-metric low-risk">
                <h5>✅ Low Risk Segment</h5>
                <p>Customers: {business_impact.segment_breakdown.low_risk.count}</p>
                <p>Avg Probability: {(business_impact.segment_breakdown.low_risk.avg_probability * 100).toFixed(1)}%</p>
                <p>Potential Loss: ₹{(business_impact.segment_breakdown.low_risk.potential_loss / 1000).toFixed(0)}K</p>
              </div>
            </div>
          </div>
        )}

        {highRiskCount > 0 && (
          <div className="critical-insights">
            <h4>🎯 Critical Business Insights</h4>
            <p>
              The <strong>{highRiskCount} high-risk customers</strong> account for a potential loss of{' '}
              <strong>₹{business_impact?.total_potential_loss?.toLocaleString() || 'N/A'}</strong>.{' '}
              Immediate intervention is recommended to prevent revenue leakage.
            </p>
            <div className="insight-actions">
              <button className="insight-btn primary">🚀 Launch Retention Campaign</button>
              <button className="insight-btn secondary">📞 Schedule Executive Review</button>
            </div>
          </div>
        )}
      </div>
    );
  };

  const downloadAllData = () => {
    if (!results || !results.sample_predictions) return;

    const allData = results.sample_predictions.map(item => ({
      ...item,
      Churn_Probability: (item.Churn_Probability * 100).toFixed(2) + '%'
    }));

    const csvContent = [
      Object.keys(allData[0]).join(','),
      ...allData.map(row => Object.values(row).join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv' });
    const url = URL.createObjectURL(blob);
    
    const a = document.createElement('a');
    a.href = url;
    a.download = `complete_churn_analysis_${new Date().toISOString().split('T')[0]}.csv`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const renderResults = () => {
    if (!results || !filteredData) return null;

    const displayData = filteredData || results.sample_predictions || [];

    // Group data by risk level for segmentation
    const highRiskData = displayData.filter(item => item.Risk_Level === 'P1: High Risk (>70%)');
    const mediumRiskData = displayData.filter(item => item.Risk_Level === 'P2: Moderate Risk (31-70%)');
    const lowRiskData = displayData.filter(item => item.Risk_Level === 'P3: Low Risk (<=30%)');

    return (
      <div className="batch-results">
        <div className="results-header">
          <h3>📊 Batch Analysis Results</h3>
          <div className="results-meta">
            <span className="data-source">
              Source: {results.data_source === 'simulated' ? 'Demo Data' : 'Uploaded File'}
            </span>
            <span className="processing-time">
              Processed in {results.processing_time_seconds}s
            </span>
            <span className="model-used">
              Model: {results.model_used === 'ml_model' ? 'Production ML' : 'Smart Logic'}
            </span>
          </div>
        </div>
        
        {/* Filters */}
        <div className="filters-section">
          <h4>🔍 Filter Customer Segments</h4>
          <div className="filter-grid">
            <div className="filter-group">
              <label>Risk Level</label>
              <select 
                multiple
                value={filters.riskLevels}
                onChange={(e) => {
                  const selected = Array.from(e.target.selectedOptions, option => option.value);
                  handleFilterChange('riskLevels', selected);
                }}
                className="multi-select"
              >
                <option value="P1: High Risk (>70%)">🚨 High Risk</option>
                <option value="P2: Moderate Risk (31-70%)">⚠️ Moderate Risk</option>
                <option value="P3: Low Risk (<=30%)">✅ Low Risk</option>
              </select>
            </div>
            
            <div className="filter-group">
              <label>Tenure Range (Months)</label>
              <div className="range-inputs">
                <input 
                  type="number" 
                  value={filters.tenureRange[0]}
                  onChange={(e) => handleFilterChange('tenureRange', [parseInt(e.target.value), filters.tenureRange[1]])}
                  min="0"
                  max="200"
                />
                <span>to</span>
                <input 
                  type="number" 
                  value={filters.tenureRange[1]}
                  onChange={(e) => handleFilterChange('tenureRange', [filters.tenureRange[0], parseInt(e.target.value)])}
                  min="0"
                  max="200"
                />
              </div>
            </div>
            
            <div className="filter-group">
              <label>Order Count Range</label>
              <div className="range-inputs">
                <input 
                  type="number" 
                  value={filters.ordersRange[0]}
                  onChange={(e) => handleFilterChange('ordersRange', [parseInt(e.target.value), filters.ordersRange[1]])}
                  min="0"
                  max="100"
                />
                <span>to</span>
                <input 
                  type="number" 
                  value={filters.ordersRange[1]}
                  onChange={(e) => handleFilterChange('ordersRange', [filters.ordersRange[0], parseInt(e.target.value)])}
                  min="0"
                  max="100"
                />
              </div>
            </div>
          </div>
          <div className="filter-stats">
            Showing {filteredData?.length || 0} of {results.sample_predictions?.length || 0} customers
          </div>
        </div>

        {/* Tabs */}
        <div className="results-tabs">
          <button 
            className={`tab-button ${activeTab === 'scorecard' ? 'active' : ''}`}
            onClick={() => setActiveTab('scorecard')}
          >
            ⭐ Executive Scorecard
          </button>
          <button 
            className={`tab-button ${activeTab === 'segmentation' ? 'active' : ''}`}
            onClick={() => setActiveTab('segmentation')}
          >
            💡 Actionable Segmentation
          </button>
          <button 
            className={`tab-button ${activeTab === 'analytics' ? 'active' : ''}`}
            onClick={() => setActiveTab('analytics')}
          >
            📈 Detailed Analytics
          </button>
        </div>

        {/* Tab Content */}
        <div className="tab-content">
          {activeTab === 'scorecard' && renderExecutiveScorecard()}
          
          {activeTab === 'segmentation' && (
            <div className="segmentation-view">
              <h3>💡 Actionable Customer Segmentation</h3>
              <div className="segmentation-grid">
                <div className="segment-column">
                  {renderSegmentCard(highRiskData, 'High', '#ef4444', '🚨', 'P1: High Risk (>70%)')}
                </div>
                <div className="segment-column">
                  {renderSegmentCard(mediumRiskData, 'Medium', '#f97316', '⚠️', 'P2: Moderate Risk (31-70%)')}
                </div>
                <div className="segment-column">
                  {renderSegmentCard(lowRiskData, 'Low', '#34d399', '✅', 'P3: Low Risk (<=30%)')}
                </div>
              </div>
              
              <div className="download-all-section">
                <button className="download-all-btn" onClick={downloadAllData}>
                  📥 Download Complete Analysis CSV ({results.sample_predictions?.length || 0} records)
                </button>
                <p className="download-note">
                  Includes all customer data with churn predictions and risk levels for CRM import
                </p>
              </div>
            </div>
          )}
          
          {activeTab === 'analytics' && (
            <div className="analytics-view">
              <h3>📈 Visual Analytics & Insights</h3>
              
              <div className="charts-grid">
                <div className="chart-row full-width">
                  {renderRiskDistributionChart()}
                </div>
                
                <div className="chart-row full-width">
                  {renderProbabilityDistribution()}
                </div>
                
                <div className="chart-row">
                  {renderFeatureAnalysis()}
                </div>
                
                <div className="chart-row full-width">
                  {renderValueRiskAnalysis()}
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    );
  };

  return (
    <div className="batch-analysis">
      <div className="analysis-container">
        <div className="section-card">
          <div className="file-upload-area">
            <input
              type="file"
              accept=".csv"
              onChange={handleFileSelect}
              className="file-input"
              id="batch-file"
            />
            <label htmlFor="batch-file" className="file-label">
              <span className="btn-icon">📎</span>
              Choose CSV File
            </label>
            
            {selectedFile && (
              <div className="file-info">
                <span className="file-success">✅</span>
                <div className="file-details">
                  <strong>{selectedFile.name}</strong>
                  <span>{(selectedFile.size / 1024).toFixed(1)} KB</span>
                </div>
              </div>
            )}
            
            <div className="file-requirements">
              <p><strong>Required format:</strong> CSV with customer features including Tenure, OrderCount, CashbackAmount, DaySinceLastOrder, etc.</p>
              <p><small>Don't have a file? The system will use demo data for analysis.</small></p>
            </div>
          </div>

          <div className="action-buttons-bottom">
            <button 
              className="action-btn primary" 
              onClick={onAnalyze} 
              disabled={loading}
            >
              {loading ? (
                <>
                  <div className="spinner"></div>
                  Processing Batch Analysis...
                </>
              ) : (
                <>
                  <span className="btn-icon">🚀</span>
                  Analyze Customer Data
                </>
              )}
            </button>
          </div>
        </div>

        {renderResults()}
      </div>
    </div>
  );
}

export default BatchAnalysis;
